using LaPlateformeDeLemploiAPI.Models;
using Microsoft.EntityFrameworkCore;

namespace LaPlateformeDeLemploiAPI.Data;

public class AppDbContext : DbContext
{
    public AppDbContext(DbContextOptions<AppDbContext> options) : base(options) { }

    public DbSet<JobOffer> JobOffers => Set<JobOffer>();
    public DbSet<Company> Companies => Set<Company>();
    public DbSet<Category> Categories => Set<Category>();
    public DbSet<User> Users => Set<User>();
    public DbSet<Application> Applications => Set<Application>();
    public DbSet<Favorite> Favorites => Set<Favorite>();
    public DbSet<Notification> Notifications => Set<Notification>();
    public DbSet<Resume> Resumes => Set<Resume>();
    public DbSet<ResumeExperience> ResumeExperiences => Set<ResumeExperience>();
    public DbSet<ResumeEducation> ResumeEducations => Set<ResumeEducation>();
    public DbSet<ResumeSkill> ResumeSkills => Set<ResumeSkill>();
    public DbSet<ResumeLanguage> ResumeLanguages => Set<ResumeLanguage>();
    public DbSet<JobPreferences> JobPreferences => Set<JobPreferences>();
    public DbSet<SpontaneousApplication> SpontaneousApplications => Set<SpontaneousApplication>();
    public DbSet<Interview> Interviews => Set<Interview>();
    public DbSet<JobTemplate> JobTemplates => Set<JobTemplate>();
    public DbSet<Conversation> Conversations => Set<Conversation>();
    public DbSet<Message> Messages => Set<Message>();
    public DbSet<CompanyReview> CompanyReviews => Set<CompanyReview>();

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        base.OnModelCreating(modelBuilder);

        modelBuilder.Entity<Company>(entity =>
        {
            entity.HasKey(e => e.Id);
            entity.Property(e => e.Name).IsRequired().HasMaxLength(200);
            entity.Property(e => e.Description).HasMaxLength(2000);
            entity.Property(e => e.LogoUrl).HasMaxLength(500);
            entity.Property(e => e.Website).HasMaxLength(500);
            entity.Property(e => e.Location).HasMaxLength(200);
        });

        modelBuilder.Entity<Category>(entity =>
        {
            entity.HasKey(e => e.Id);
            entity.Property(e => e.Name).IsRequired().HasMaxLength(100);
            entity.Property(e => e.Icon).HasMaxLength(50);
        });

        modelBuilder.Entity<JobOffer>(entity =>
        {
            entity.HasKey(e => e.Id);
            entity.Property(e => e.Title).IsRequired().HasMaxLength(200);
            entity.Property(e => e.Description).IsRequired().HasMaxLength(5000);
            entity.Property(e => e.Location).IsRequired().HasMaxLength(200);
            entity.Property(e => e.ContractType).IsRequired().HasMaxLength(50);
            entity.Property(e => e.SalaryMin).HasColumnType("decimal(10,2)");
            entity.Property(e => e.SalaryMax).HasColumnType("decimal(10,2)");

            entity.HasOne(e => e.Company)
                .WithMany(c => c.JobOffers)
                .HasForeignKey(e => e.CompanyId)
                .OnDelete(DeleteBehavior.Cascade);

            entity.HasOne(e => e.Category)
                .WithMany(c => c.JobOffers)
                .HasForeignKey(e => e.CategoryId)
                .OnDelete(DeleteBehavior.Cascade);
        });

        modelBuilder.Entity<User>(entity =>
        {
            entity.HasKey(e => e.Id);
            entity.Property(e => e.Email).IsRequired().HasMaxLength(200);
            entity.HasIndex(e => e.Email).IsUnique();
            entity.Property(e => e.PasswordHash).IsRequired();
            entity.Property(e => e.FirstName).IsRequired().HasMaxLength(100);
            entity.Property(e => e.LastName).IsRequired().HasMaxLength(100);
            entity.Property(e => e.Role).IsRequired().HasMaxLength(20);
            entity.Property(e => e.Phone).HasMaxLength(20);
            entity.Property(e => e.Bio).HasMaxLength(2000);
            entity.Property(e => e.Skills).HasMaxLength(1000);
            entity.Property(e => e.ResumeUrl).HasMaxLength(500);

            entity.HasOne(e => e.Company)
                .WithMany()
                .HasForeignKey(e => e.CompanyId)
                .OnDelete(DeleteBehavior.SetNull);
        });

        modelBuilder.Entity<Application>(entity =>
        {
            entity.HasKey(e => e.Id);
            entity.Property(e => e.CoverLetter).HasMaxLength(3000);
            entity.Property(e => e.Status).IsRequired().HasMaxLength(20);
            entity.HasIndex(e => new { e.UserId, e.JobOfferId }).IsUnique();

            entity.HasOne(e => e.User).WithMany().HasForeignKey(e => e.UserId).OnDelete(DeleteBehavior.Cascade);
            entity.HasOne(e => e.JobOffer).WithMany().HasForeignKey(e => e.JobOfferId).OnDelete(DeleteBehavior.Cascade);
        });

        modelBuilder.Entity<Favorite>(entity =>
        {
            entity.HasKey(e => e.Id);
            entity.HasIndex(e => new { e.UserId, e.JobOfferId }).IsUnique();

            entity.HasOne(e => e.User).WithMany().HasForeignKey(e => e.UserId).OnDelete(DeleteBehavior.Cascade);
            entity.HasOne(e => e.JobOffer).WithMany().HasForeignKey(e => e.JobOfferId).OnDelete(DeleteBehavior.NoAction);
        });

        modelBuilder.Entity<JobPreferences>(entity =>
        {
            entity.HasKey(e => e.Id);
            entity.HasIndex(e => e.UserId).IsUnique();
            entity.HasOne(e => e.User).WithMany().HasForeignKey(e => e.UserId).OnDelete(DeleteBehavior.Cascade);
            entity.Property(e => e.DesiredContractTypes).HasMaxLength(200);
            entity.Property(e => e.DesiredLocations).HasMaxLength(500);
            entity.Property(e => e.DesiredCategoryIds).HasMaxLength(100);
            entity.Property(e => e.Keywords).HasMaxLength(1000);
            entity.Property(e => e.MinSalary).HasColumnType("decimal(10,2)");
        });

        modelBuilder.Entity<Resume>(entity =>
        {
            entity.HasKey(e => e.Id);
            entity.Property(e => e.Title).IsRequired().HasMaxLength(200);
            entity.Property(e => e.Summary).HasMaxLength(2000);
            entity.HasOne(e => e.User).WithMany().HasForeignKey(e => e.UserId).OnDelete(DeleteBehavior.Cascade);
            entity.HasMany(e => e.Experiences).WithOne(e => e.Resume).HasForeignKey(e => e.ResumeId).OnDelete(DeleteBehavior.Cascade);
            entity.HasMany(e => e.Educations).WithOne(e => e.Resume).HasForeignKey(e => e.ResumeId).OnDelete(DeleteBehavior.Cascade);
            entity.HasMany(e => e.Skills).WithOne(e => e.Resume).HasForeignKey(e => e.ResumeId).OnDelete(DeleteBehavior.Cascade);
            entity.HasMany(e => e.Languages).WithOne(e => e.Resume).HasForeignKey(e => e.ResumeId).OnDelete(DeleteBehavior.Cascade);
        });

        modelBuilder.Entity<ResumeExperience>(e => { e.Property(x => x.JobTitle).IsRequired().HasMaxLength(200); e.Property(x => x.Company).IsRequired().HasMaxLength(200); e.Property(x => x.Description).HasMaxLength(2000); });
        modelBuilder.Entity<ResumeEducation>(e => { e.Property(x => x.Degree).IsRequired().HasMaxLength(200); e.Property(x => x.School).IsRequired().HasMaxLength(200); e.Property(x => x.Description).HasMaxLength(2000); });
        modelBuilder.Entity<ResumeSkill>(e => { e.Property(x => x.Name).IsRequired().HasMaxLength(100); });
        modelBuilder.Entity<ResumeLanguage>(e => { e.Property(x => x.Name).IsRequired().HasMaxLength(100); e.Property(x => x.Level).IsRequired().HasMaxLength(50); });

        modelBuilder.Entity<Notification>(entity =>
        {
            entity.HasKey(e => e.Id);
            entity.Property(e => e.Title).IsRequired().HasMaxLength(200);
            entity.Property(e => e.Message).IsRequired().HasMaxLength(500);
            entity.Property(e => e.Type).IsRequired().HasMaxLength(20);
            entity.Property(e => e.Link).HasMaxLength(300);
            entity.HasOne(e => e.User).WithMany().HasForeignKey(e => e.UserId).OnDelete(DeleteBehavior.Cascade);
        });

        modelBuilder.Entity<JobTemplate>(entity =>
        {
            entity.HasKey(e => e.Id);
            entity.Property(e => e.Name).IsRequired().HasMaxLength(200);
            entity.Property(e => e.Title).IsRequired().HasMaxLength(200);
            entity.Property(e => e.Description).IsRequired().HasMaxLength(5000);
            entity.Property(e => e.Location).HasMaxLength(200);
            entity.Property(e => e.ContractType).HasMaxLength(50);
            entity.Property(e => e.SalaryMin).HasColumnType("decimal(10,2)");
            entity.Property(e => e.SalaryMax).HasColumnType("decimal(10,2)");
            entity.HasOne(e => e.Company).WithMany().HasForeignKey(e => e.CompanyId).OnDelete(DeleteBehavior.Cascade);
        });

        modelBuilder.Entity<Interview>(entity =>
        {
            entity.HasKey(e => e.Id);
            entity.Property(e => e.Type).IsRequired().HasMaxLength(20);
            entity.Property(e => e.Location).HasMaxLength(500);
            entity.Property(e => e.Notes).HasMaxLength(1000);
            entity.Property(e => e.Status).IsRequired().HasMaxLength(20);
            entity.HasOne(e => e.Application).WithMany().HasForeignKey(e => e.ApplicationId).OnDelete(DeleteBehavior.Cascade);
            entity.HasOne(e => e.CompanyUser).WithMany().HasForeignKey(e => e.CompanyUserId).OnDelete(DeleteBehavior.NoAction);
            entity.HasOne(e => e.CandidateUser).WithMany().HasForeignKey(e => e.CandidateUserId).OnDelete(DeleteBehavior.NoAction);
        });

        modelBuilder.Entity<SpontaneousApplication>(entity =>
        {
            entity.HasKey(e => e.Id);
            entity.Property(e => e.CoverLetter).HasMaxLength(3000);
            entity.Property(e => e.Status).IsRequired().HasMaxLength(20);
            entity.HasIndex(e => new { e.UserId, e.CompanyId }).IsUnique();
            entity.HasOne(e => e.User).WithMany().HasForeignKey(e => e.UserId).OnDelete(DeleteBehavior.Cascade);
            entity.HasOne(e => e.Company).WithMany().HasForeignKey(e => e.CompanyId).OnDelete(DeleteBehavior.NoAction);
        });

        modelBuilder.Entity<Conversation>(entity =>
        {
            entity.HasKey(e => e.Id);
            entity.HasOne(e => e.User1).WithMany().HasForeignKey(e => e.User1Id).OnDelete(DeleteBehavior.NoAction);
            entity.HasOne(e => e.User2).WithMany().HasForeignKey(e => e.User2Id).OnDelete(DeleteBehavior.NoAction);
            entity.HasIndex(e => new { e.User1Id, e.User2Id }).IsUnique();
        });

        modelBuilder.Entity<Message>(entity =>
        {
            entity.HasKey(e => e.Id);
            entity.Property(e => e.Content).IsRequired().HasMaxLength(2000);
            entity.HasOne(e => e.Conversation).WithMany(c => c.Messages).HasForeignKey(e => e.ConversationId).OnDelete(DeleteBehavior.Cascade);
            entity.HasOne(e => e.Sender).WithMany().HasForeignKey(e => e.SenderId).OnDelete(DeleteBehavior.NoAction);
        });

        modelBuilder.Entity<CompanyReview>(entity =>
        {
            entity.HasKey(e => e.Id);
            entity.Property(e => e.Comment).HasMaxLength(1000);
            entity.Property(e => e.InterviewPosition).HasMaxLength(100);
            entity.HasIndex(e => new { e.UserId, e.CompanyId }).IsUnique();
            entity.HasOne(e => e.User).WithMany().HasForeignKey(e => e.UserId).OnDelete(DeleteBehavior.Cascade);
            entity.HasOne(e => e.Company).WithMany().HasForeignKey(e => e.CompanyId).OnDelete(DeleteBehavior.NoAction);
        });

        SeedData(modelBuilder);
    }

